import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_KEY });
const vex = new Vex({ apiKey: process.env.VEX_KEY });

// Claude computer use with tool
let response = await anthropic.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools: [{ type: 'computer', commands: ['look', 'type', 'click'] }],
  messages: [{ role: 'user', content: 'Update billing dashboard for tenant 789' }]
});

// Vex verifies screen action safety
const result = await vex.verify('computer-use-safety', {
  claudeResponse: response,
  tenantId: '789',
  screenElements: response.content,
  intendedAction: 'update_billing',
  policies: ['no_production_deletes', 'tenant_boundary_check']
});

if (!result.passed) {
  console.error('Blocked unsafe action:', result.reason);
  // Log SOC 2 audit trail
  await logAuditEvent(result);
  throw new Error('Compliance violation');
}
